// Generated by AI (UnitTest MCP)
use std::collections::{HashMap, HashSet};

use crate::ingest::execution::ExecutionRecord;
use crate::ingest::git::CommitRecord;
use crate::ingest::structure::{HierarchyRelation, ImportTarget};
use crate::{
    ingest, now_unix, ArtifactStub, Edge, ForgetOutcome, MindLeak, Node, NodeType,
    ReconcileOutcome, RelationType, Result, WriteOutcome,
};

impl MindLeak {
    /// Record that one explicit session agent observed these nodes.
    pub(super) fn observe(&self, agent: &str, ids: &[String], now: i64) -> Result<()> {
        let agent = agent.trim().strip_prefix("agent:").unwrap_or(agent.trim());
        if agent.is_empty() {
            return Ok(());
        }
        let agent_id = format!("agent:{agent}");
        self.store
            .upsert_node(&Node::new(&agent_id, NodeType::Agent, agent, now))?;
        for id in ids {
            if id == &agent_id {
                continue;
            }
            let mut edge = Edge::new(&agent_id, id, RelationType::Observed, now);
            // Attribution of a transient execution must not outlive the
            // execution's own evidence. Left at the generic `observed` half-life
            // (48h) the attribution edge pins the execution in the graph for
            // roughly twice as long as its 24h `modified` evidence, so prune
            // cannot reap the spent execution until ~9 days out. Cap execution
            // attribution to the execution decay tier so both fade together and
            // the orphaned execution is reaped promptly (ADR-0021 / ADR-0003).
            if id.starts_with("execution:") {
                edge.half_life_hours = RelationType::Modified.default_half_life_hours();
            }
            self.store.upsert_edge(&edge)?;
        }
        Ok(())
    }

    // ---- ingestion ----------------------------------------------------------

    pub fn ingest_execution(&self, rec: &ExecutionRecord) -> Result<WriteOutcome> {
        let now = now_unix();
        ingest::execution::ingest_execution(&self.store, rec, now)
    }

    pub fn ingest_execution_for_agent(
        &self,
        agent: &str,
        rec: &ExecutionRecord,
    ) -> Result<WriteOutcome> {
        let now = now_unix();
        let outcome = ingest::execution::ingest_execution(&self.store, rec, now)?;
        self.observe(agent, &outcome.node_ids, now)?;
        Ok(outcome)
    }

    pub fn ingest_commit(&self, rec: &CommitRecord) -> Result<WriteOutcome> {
        let now = now_unix();
        ingest::git::ingest_commit(&self.store, rec, now)
    }

    pub fn ingest_commit_for_agent(&self, agent: &str, rec: &CommitRecord) -> Result<WriteOutcome> {
        let now = now_unix();
        let outcome = ingest::git::ingest_commit(&self.store, rec, now)?;
        self.observe(agent, &outcome.node_ids, now)?;
        Ok(outcome)
    }

    /// Forget a deleted file: reap its structure (the symbols it defined and the
    /// artifact node) and every edge touching them. Called when the workspace
    /// reports a file removed or renamed, so the graph stops carrying structure
    /// for a path that no longer exists instead of waiting ~a month for it to
    /// decay. A no-op when the path was never ingested.
    pub fn forget_file(&self, path: &str) -> Result<ForgetOutcome> {
        let norm = ingest::normalize_path(path);
        let artifact_id = format!("artifact:{norm}");
        self.store.forget_artifact(&artifact_id)
    }

    /// Reconcile the graph against the workspace's current file set: forget every
    /// file artifact whose path is not in `current_paths` (deleted or moved
    /// outside the editor's delete events) or is build/VCS junk. This cleans
    /// stale structure in one pass rather than waiting ~a month for it to decay,
    /// and catches deletions the editor's `forget_file` hook cannot see (e.g. a
    /// terminal `git rm` or an external move).
    pub fn reconcile_workspace(&self, current_paths: &[String]) -> Result<ReconcileOutcome> {
        let keep: HashSet<String> = current_paths
            .iter()
            .map(|p| ingest::normalize_path(p))
            .collect();
        let mut outcome = ReconcileOutcome::default();
        for artifact_id in self.store.artifact_ids()? {
            let path = artifact_id
                .strip_prefix("artifact:")
                .unwrap_or(&artifact_id);
            if ingest::is_ignored_path(path) || !keep.contains(path) {
                let forgotten = self.store.forget_artifact(&artifact_id)?;
                if forgotten.nodes_removed > 0 || forgotten.edges_removed > 0 {
                    outcome.files_forgotten += 1;
                    outcome.nodes_removed += forgotten.nodes_removed;
                    outcome.edges_removed += forgotten.edges_removed;
                }
            }
        }
        Ok(outcome)
    }

    /// Replace a source file's authoritative structural snapshot.
    pub fn ingest_file(&self, path: &str, content: &str) -> Result<WriteOutcome> {
        self.ingest_file_inner(path, content, None)
    }

    pub fn ingest_file_for_agent(
        &self,
        agent: &str,
        path: &str,
        content: &str,
    ) -> Result<WriteOutcome> {
        self.ingest_file_inner(path, content, Some(agent))
    }

    fn ingest_file_inner(
        &self,
        path: &str,
        content: &str,
        agent: Option<&str>,
    ) -> Result<WriteOutcome> {
        let now = now_unix();
        let norm = ingest::normalize_path(path);
        // VCS internals, dependency caches, and build/test output are not source
        // and only pollute the graph with structure for paths that vanish.
        if ingest::is_ignored_path(&norm) {
            return Ok(WriteOutcome::default());
        }
        let art_id = format!("artifact:{norm}");
        let art = Node::new(&art_id, NodeType::Artifact, norm.clone(), now);
        let mut nodes = vec![art];
        let mut edges = Vec::new();
        let mut artifact_stubs = Vec::new();
        let mut imported_symbols: HashMap<String, (String, String)> = HashMap::new();

        let extraction = ingest::ast::extract(path, content);
        let local_symbols: HashSet<&str> = extraction
            .symbols
            .iter()
            .map(|symbol| symbol.name.as_str())
            .collect();
        for sym in &extraction.symbols {
            let sym_id = format!("symbol:{norm}:{}", sym.name);
            let label = format!("{} ({})", sym.name, sym.kind);
            let node = Node::new(&sym_id, NodeType::Symbol, label, now)
                .with_content(format!("{}:{}", norm, sym.line));
            nodes.push(node);
            edges.push(Edge::new(&art_id, &sym_id, RelationType::Contains, now));
        }

        // In-file call edges (symbol -> symbol); both endpoints exist as nodes.
        for call in &extraction.calls {
            let from = format!("symbol:{norm}:{}", call.caller);
            let to = format!("symbol:{norm}:{}", call.callee);
            edges.push(Edge::new(&from, &to, RelationType::Calls, now));
        }

        for import in ingest::structure::extract(path, content) {
            let target_id = match import.target {
                ImportTarget::ArtifactCandidates(candidates) => {
                    let known = self.store.resolve_artifact_candidate(&candidates)?;
                    let is_stub = known.is_none();
                    let Some(target_path) = known.or_else(|| candidates.first().cloned()) else {
                        continue;
                    };
                    let target_id = format!("artifact:{target_path}");
                    if is_stub {
                        artifact_stubs.push(ArtifactStub {
                            node_id: target_id.clone(),
                            candidate_ids: candidates
                                .iter()
                                .map(|path| format!("artifact:{path}"))
                                .collect(),
                        });
                    }
                    nodes.push(Node::new(
                        &target_id,
                        NodeType::Artifact,
                        target_path.clone(),
                        now,
                    ));
                    for binding in import.bindings {
                        if binding.imported != "default" && binding.imported != "*" {
                            imported_symbols
                                .insert(binding.local, (target_path.clone(), binding.imported));
                        }
                    }
                    target_id
                }
                ImportTarget::Package(package) => {
                    let target_id = format!("package:{package}");
                    nodes.push(Node::new(
                        &target_id,
                        NodeType::Package,
                        package.clone(),
                        now,
                    ));
                    target_id
                }
            };
            edges.push(Edge::new(&art_id, target_id, RelationType::Imports, now));
        }

        for hierarchy in ingest::structure::extract_hierarchy(path, content) {
            if !local_symbols.contains(hierarchy.source.as_str()) {
                continue;
            }
            let (target_path, target_name) = if local_symbols.contains(hierarchy.target.as_str()) {
                (norm.as_str(), hierarchy.target.as_str())
            } else if let Some((path, name)) = imported_symbols.get(&hierarchy.target) {
                (path.as_str(), name.as_str())
            } else {
                continue;
            };
            let source_id = format!("symbol:{norm}:{}", hierarchy.source);
            let target_id = format!("symbol:{target_path}:{target_name}");
            if !self.store.node_exists(&target_id)? {
                nodes.push(Node::new(
                    &target_id,
                    NodeType::Symbol,
                    format!("{target_name} (imported)"),
                    now,
                ));
            }
            let relation = match hierarchy.relation {
                HierarchyRelation::Extends => RelationType::Extends,
                HierarchyRelation::Implements => RelationType::Implements,
            };
            edges.push(Edge::new(source_id, target_id, relation, now));
        }

        if let Some(dependencies) = ingest::manifest::extract(path, content)? {
            for dependency in dependencies {
                let target_id = format!("package:{}", dependency.name);
                nodes.push(Node::new(
                    &target_id,
                    NodeType::Package,
                    dependency.name,
                    now,
                ));
                edges.push(Edge::new(&art_id, target_id, RelationType::DependsOn, now));
            }
        }

        for reference in &extraction.call_references {
            let Some((target_path, imported_name)) = imported_symbols.get(&reference.callee) else {
                continue;
            };
            let from = format!("symbol:{norm}:{}", reference.caller);
            let to = format!("symbol:{target_path}:{imported_name}");
            if !self.store.node_exists(&to)? {
                nodes.push(Node::new(
                    &to,
                    NodeType::Symbol,
                    format!("{imported_name} (imported)"),
                    now,
                ));
            }
            edges.push(Edge::new(from, to, RelationType::Calls, now));
        }

        let mut outcome = self
            .store
            .replace_structure(&art_id, &nodes, &edges, &artifact_stubs)?;
        outcome.node_ids.push(art_id.clone());
        if let Some(agent) = agent {
            self.observe(agent, &outcome.node_ids, now)?;
        }
        Ok(outcome)
    }

    /// Record node attention for recency displays without rewriting evidence.
    pub fn boost(&self, id: &str) -> Result<bool> {
        self.store.boost(id, now_unix())
    }

    pub fn boost_for_agent(&self, agent: &str, id: &str) -> Result<bool> {
        let now = now_unix();
        let boosted = self.store.boost(id, now)?;
        if boosted {
            self.observe(agent, &[id.to_string()], now)?;
        }
        Ok(boosted)
    }
}
